patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4bba2f406b4c..b05536865f2a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2793,7 +2793,16 @@ static Instruction *foldSelectWithFCmpToFabs(SelectInst &SI,

     // fold (X <= +/-0.0) ? (0.0 - X) : X to fabs(X), when 'Swap' is false
     // fold (X >  +/-0.0) ? X : (0.0 - X) to fabs(X), when 'Swap' is true
+    // Note: We require "nnan" for this fold because fcmp ignores the signbit
+    //       of NAN, but IEEE-754 specifies the signbit of NAN values with
+    //       fneg/fabs operations.
     if (match(TrueVal, m_FSub(m_PosZeroFP(), m_Specific(X)))) {
+      // Check if we have NoNaNs semantics from either the select or the fcmp
+      // or if we can prove X is never NaN through other means (e.g., nofpclass)
+      FastMathFlags FMF = cast<FPMathOperator>(CondVal)->getFastMathFlags();
+      if (!SI.hasNoNaNs() && !FMF.noNaNs() &&
+          !computeKnownFPClass(X, FMF, fcNan, 0, IC.getSimplifyQuery().getWithInstruction(&SI)).isKnownNeverNaN())
+        continue;
       if (!Swap && (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE)) {
         Value *Fabs = IC.Builder.CreateUnaryIntrinsic(Intrinsic::fabs, X, &SI);
         return IC.replaceInstUsesWith(SI, Fabs);

